const back_to_list = backCmds.includes(msg.toLowerCase());
const mode = item.mode || null;

var action_choice = null;
if (item.action_choice !== undefined && item.action_choice !== null && item.action_choice !== '') {
  var acParsed = parseInt(String(item.action_choice), 10);
  if (!isNaN(acParsed)) action_choice = acParsed;
} else if (mode === 'project_action_menu' && msg.match(/^\d+$/)) {
  action_choice = parseInt(msg, 10);
}

var project_choice = null;
if (item.project_choice !== undefined && item.project_choice !== null && item.project_choice !== '') {
  var pcParsed = parseInt(String(item.project_choice), 10);
  if (!isNaN(pcParsed)) project_choice = pcParsed;
} else if (action_choice === null && !back_to_list && (mode === 'project_selection' || mode === null) && msg.match(/^\d+$/)) {
  project_choice = parseInt(msg, 10);
}

var project_title = item.project_title || null;
if (!project_title && mode === 'new_project_intake' && msg && !back_to_list && !msg.match(/^\d+$/)) {
  project_title = msg;
}

var approved = false;
if (item.approved === true || (typeof item.approved === 'string' && item.approved.toLowerCase() === 'true')) {
  approved = true;
} else if (msg.match(/^(yes|approve|proceed|start|go ahead|\u05db\u05df|\u05d0\u05d9\u05e9\u05d5\u05e8)$/i)) {
  approved = true;
}

const hasActionable = item.project_id || project_choice !== null || action_choice !== null || project_title || back_to_list || mode;
if (!msg && !hasActionable) {
  return [{ json: { error: true, error_type: 'VALIDATION_FAILED', message: '\u05e7\u05dc\u05d8 \u05d7\u05e1\u05e8.', request_id: item.request_id || ('req_' + Date.now()), timestamp: new Date().toISOString() } }];
}

return [{ json: {
  request_id: item.request_id || ('req_' + Date.now()),
  user_id: item.user_id || 'anonymous',
  message: msg,
